@Service
public class UserService {

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private BCryptPasswordEncoder passwordEncoder;

    public User enableMFA(User user) {
        String recoveryCode = generateRecoveryCode();
        user.setRecoveryCode(passwordEncoder.encode(recoveryCode));
        userRepository.save(user);
        return user;
    }

    public boolean authenticateWithRecoveryCode(String username, String recoveryCode) {
        User user = userRepository.findByUsername(username);
        if (user != null && passwordEncoder.matches(recoveryCode, user.getRecoveryCode())) {
            return true;
        }
        return false;
    }

    private String generateRecoveryCode() {
        // Generate a secure random 12-character recovery code
        SecureRandom random = new SecureRandom();
        byte[] bytes = new byte[6];
        random.nextBytes(bytes);
        BigInteger bigInt = new BigInteger(1, bytes);
        return String.format("%012d", bigInt).replace('0', 'A');
    }
}

